import scala.xml.XML
import scala.io.Source

object ConfigService {
  def parseXml(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    (xml \\ "*").flatMap { node =>
      for {
        key <- node.attribute("key")
        value <- node.text
      } yield (key.toString -> value.trim)
    }.toMap
  }

  def main(args: Array[String]): Unit = {
    val xmlString =
      """<config>
          |  <setting key="database.url">jdbc:mysql://localhost/db</setting>
          |  <setting key="database.user">user</setting>
          |  <setting key="database.password">password</setting>
          |</config>""".stripMargin

    val settings = parseXml(xmlString)
    println(settings)
  }
}